163→
164→                return {
165→                    ...old,
166→                    pages: old.pages.map((page) => ({
167→                        ...page,
168→                        data: Array.isArray(page?.data)
169→                            ? page.data.filter((journal) => journal?.id !== journalId)
170→                            : page?.data
171→                    }))
172→                };
173→            });
174→
175→            const deleteJournalPromise = deleteJournal(journalId, token,)
176→            const deleteImageJournalPromise = image_url ? deleteJournalImage(token, imageUrlArray) : Promise.resolve(null);
177→
178→            const [deletePostJournal, deletePostJournalImage] = await Promise.allSettled([
179→                deleteJournalPromise,
180→                deleteImageJournalPromise,
181→            ])
182→            if(deletePostJournal || deletePostJournalImage){
183→                console.log({deletePostJournal: deletePostJournal, deletePostJournalImage: deletePostJournalImage})
184→            }
185→
186→            if(deletePostJournal.status !== 'fulfilled'){
187→                queryClient.setQueryData(queryKey, previousUserJournals);
188→                throw deletePostJournal.reason || new Error('failed to delete journal');
189→            }
190→
191→            setJournalIsDeleted(true)
192→            queryClient.invalidateQueries({ queryKey: queryKey });
193→            queryClient.invalidateQueries({ queryKey: ['journals'] });
194→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
195→
196→            setTimeout(() =>{
197→                setIsDeletingJournal(false)
198→                setJournalIsDeleted(false)
199→                setShowConfirmationBttn(null)
200→            }, 1500)

