/* ── Related Posts Section ── */

.rp-section {
    margin-top: 0;
    padding-top: 1rem;
    border-top: 1px solid var(--border-light);
    padding-bottom: 5rem;
    max-width: 620px;
    width: 100%;
    padding-left: 24px;
    padding-right: 24px;
    box-sizing: border-box;
}

.rp-heading {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 700;
    letter-spacing: 0.06rem;
    text-transform: uppercase;
    background: linear-gradient(135deg, var(--accent-amber), var(--accent-purple));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin: 0 0 1rem 0;
}

.rp-heading-icon {
    width: 15px;
    height: 15px;
    flex-shrink: 0;
    color: var(--accent-amber);
    filter: drop-shadow(0 0 3px rgba(212, 168, 83, 0.35));
    animation: rp-icon-pulse 3s ease-in-out infinite;
}

@keyframes rp-icon-pulse {
    0%, 100% { opacity: 0.8; transform: scale(1); }
    50% { opacity: 1; transform: scale(1.1); }
}

.rp-heading::after {
    content: '';
    flex: 1;
    height: 1px;
    background: linear-gradient(90deg, var(--accent-amber), transparent);
    opacity: 0.3;
}

/* ── Card Grid ── */

.rp-grid {
    display: flex;
    flex-direction: column;
    gap: 0.625rem;
}

/* ── Card ── */

.rp-card {
    display: flex;
    align-items: stretch;
    border-radius: 12px;
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    cursor: pointer;
    overflow: hidden;
    transition: box-shadow 0.25s ease, transform 0.25s ease, border-color 0.25s ease;
}

.rp-card:hover {
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
    transform: translateY(-1px);
    border-color: rgba(212, 168, 83, 0.2);
}

/* ── Accent Line ── */

.rp-card-accent {
    width: 3.5px;
    flex-shrink: 0;
    background: linear-gradient(180deg, var(--accent-purple), rgba(196, 148, 62, 0.5));
    border-radius: 3px 0 0 3px;
    transition: opacity 0.3s ease;
}

/* ── Card Content ── */

.rp-card-content {
    flex: 1;
    padding: 0.75rem 0.875rem;
    min-width: 0;
}

.rp-card-title {
    font-family: var(--font-serif);
    font-size: 0.875rem;
    font-weight: 500;
    color: var(--text-primary);
    margin: 0 0 0.375rem 0;
    line-height: 1.35;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.rp-card-excerpt {
    font-size: 0.78rem;
    color: var(--text-muted);
    line-height: 1.4;
    margin: 0 0 0.375rem 0;
    display: -webkit-box;
    -webkit-line-clamp: 1;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.rp-card-meta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
}

.rp-card-author {
    display: flex;
    align-items: center;
    gap: 0.375rem;
    min-width: 0;
}

.rp-card-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}

.rp-card-avatar-placeholder {
    background: var(--bg-hover);
    border: 1px solid var(--border-light);
}

.rp-card-name {
    font-size: 0.75rem;
    color: var(--text-secondary);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 140px;
}

.rp-card-date {
    font-size: 0.7rem;
    color: var(--text-muted);
    white-space: nowrap;
    flex-shrink: 0;
}

/* ── Skeleton Loading ── */

.rp-skeleton-container {
    display: flex;
    flex-direction: column;
    gap: 0.625rem;
}

.rp-skeleton-card {
    display: flex;
    align-items: stretch;
    border-radius: 12px;
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    overflow: hidden;
    height: 82px;
}

.rp-skeleton-accent {
    width: 3.5px;
    flex-shrink: 0;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
}

.rp-skeleton-content {
    flex: 1;
    padding: 0.75rem 0.875rem;
    display: flex;
    flex-direction: column;
    justify-content: center;
    gap: 0.5rem;
}

.rp-skeleton-title {
    height: 12px;
    width: 65%;
    border-radius: 4px;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
    animation-delay: 0.1s;
}

.rp-skeleton-excerpt {
    height: 10px;
    width: 85%;
    border-radius: 4px;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
    animation-delay: 0.15s;
}

.rp-skeleton-meta {
    display: flex;
    align-items: center;
    gap: 0.375rem;
}

.rp-skeleton-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
    animation-delay: 0.2s;
}

.rp-skeleton-name {
    height: 10px;
    width: 80px;
    border-radius: 4px;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
    animation-delay: 0.3s;
}

@keyframes rp-shimmer {
    0%, 100% { opacity: 0.4; }
    50% { opacity: 0.8; }
}

/* ── Responsive ── */

@media (max-width: 768px) {
    .rp-section {
        max-width: 100%;
        padding-left: 24px;
        padding-right: 24px;
    }
}

@media (max-width: 480px) {
    .rp-section {
        margin-top: 0;
        padding-top: 0.75rem;
        padding-left: 16px;
        padding-right: 16px;
        padding-bottom: 5rem;
    }

    .rp-card-name {
        max-width: 100px;
    }
}
